/* Example Python circuit breaker using a decorator (simple) */
import time
from functools import wraps

class CircuitOpen(Exception):
    pass

def circuit(failure_threshold=3, reset_timeout=10):
    state = {'fails': 0, 'open_until': 0}
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            if state['open_until'] > time.time():
                raise CircuitOpen('circuit is open')
            try:
                res = fn(*args, **kwargs)
                state['fails'] = 0
                return res
            except Exception:
                state['fails'] += 1
                if state['fails'] >= failure_threshold:
                    state['open_until'] = time.time() + reset_timeout
                raise
        return wrapper
    return decorator

# usage:
# @circuit(failure_threshold=5, reset_timeout=30)
# def call_remote():
#     ...
